import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token_str = decoded.decode('utf-8')
        token_obj = json.loads(token_str)
        return token_obj
    except (base64.binascii.Error, json.JSONDecodeError):
        return None

